import React from 'react';
import './Footer.css';

const Footer = () => {
  return (
    <footer className="footer">
      <p>⚙️ ZE<span>Motive</span> Auto Services</p>
      <p className="footer-desc">"You broke it, We fix it" — Parit Raja, Batu Pahat</p>
      <p className="copyright">© 2024 ZE Motive Auto Services. All rights reserved.</p>
      <p className="built-by">Built by Aiman</p>
    </footer>
  );
};

export default Footer;
